def metric(example, pred, trace=None):
    expected_raw = str(getattr(example, 'expected_claims', ''))
    predicted = str(getattr(pred, 'key_findings', ''))
    if not expected_raw.strip() and not predicted.strip():
        return 1.0
    if not expected_raw.strip() or not predicted.strip():
        return 0.0
    expected_claims = [c.strip().lower() for c in expected_raw.split(',') if c.strip()]
    pred_lower = predicted.lower()
    tp = sum(1 for c in expected_claims if c in pred_lower)
    precision = tp / max(1, len(predicted.split('\n')))
    recall = tp / len(expected_claims) if expected_claims else 0.0
    if precision + recall == 0:
        return 0.0
    return 2 * (precision * recall) / (precision + recall)

def metric(example, pred, trace=None):
    import re
    sources_text = str(getattr(example, 'sources', '')).lower()
    findings = str(getattr(pred, 'key_findings', ''))
    lines = [l.strip() for l in findings.split('\n') if l.strip()]
    if not lines:
        return 0.0
    verified = 0
    for line in lines:
        clean = re.sub(r'\[source \d+\]', '', line.lower()).strip()
        words = clean.split()
        if len(words) < 4:
            verified += 1
            continue
        for i in range(len(words) - 3):
            chunk = ' '.join(words[i:i+4])
            if chunk in sources_text:
                verified += 1
                break
    return verified / len(lines)

def metric(example, pred, trace=None):
    fields = ['key_findings', 'contradictions', 'gaps', 'summary']
    filled = sum(1 for f in fields if str(getattr(pred, f, '')).strip())
    return filled / len(fields)
